class TrieNode {
  char c;
  TrieNode* children[26];
  bool isEnd;
};

class Trie {
  TrieNode* root;
public:
  Trie() : root(new TrieNode()) {}
  void insert(const string& word) {
    TrieNode* node = root;
    for (char ch : word) {
      if (!node->children[ch - 'a']) node->children[ch - 'a'] = new TrieNode();
      node = node->children[ch - 'a'];
    }
    node->isEnd = true;
  }

  void print() {
    printTrie(root, 0);
  }

  void printTrie(TrieNode* node, int indent) {
    if (!node) return;
    for (int i = 0; i < 26; i++) {
      if (node->children[i]) {
        for (int j = 0; j < indent; j++) cout << '\t';
        cout << (char)('a' + i) << '\n';
        printTrie(node->children[i], indent + 1);
      }
    }
  }
};

