class Trie {
  TrieNode root;
  public Trie() {}
  public void insert(String word) {
    TrieNode node = root;
    for (char ch : word.toCharArray()) {
      if (node.children[ch - 'a'] == null) node.children[ch - 'a'] = new TrieNode();
      node = node.children[ch - 'a'];
    }
    node.isEnd = true;
  }

  public void print() {
    printTrie(root, 0);
  }

  public void printTrie(TrieNode node, int indent) {
    if (node == null) return;
    for (int i = 0; i < 26; i++) {
      if (node.children[i] != null) {
        for (int j = 0; j < indent; j++) System.out.print('\t');
        System.out.println((char)('a' + i));
        printTrie(node.children[i], indent + 1);
      }
    }
  }
}

